#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int minChildren = (N + 1) / 2;
        int maxChildren = N;
        printf("%d %d\n", minChildren, maxChildren);
    }
    return 0;
}

